mapper.insert:
insert into batch.batch_day_replay_entry (
    session_id, tenant_id, job_code, source_instance_id, rerun_instance_id,
    status, failure_reason, started_at, finished_at, result_version_id,
    created_at, updated_at
) values (
    #{sessionId}, #{tenantId}, #{jobCode}, #{sourceInstanceId}, #{rerunInstanceId},
    #{status}, #{failureReason}, #{startedAt}, #{finishedAt}, #{resultVersionId},
    #{createdAt}, #{updatedAt}
)
on conflict do nothing

mapper.select:
select * from batch.batch_day_replay_entry
where session_id = #{sessionId}
order by id asc

select * from batch.batch_day_replay_entry
where session_id = #{sessionId} and status = #{status}
order by id asc
limit #{limit}

select * from batch.batch_day_replay_entry
where tenant_id = #{tenantId} and rerun_instance_id = #{rerunInstanceId}
limit 1

select * from batch.batch_day_replay_entry
where session_id = #{sessionId}
  and tenant_id = #{tenantId}
  and source_instance_id = #{sourceInstanceId}
limit 1

select business_key, asset_code, partition_key, result_version_id as current_result_version_id, freshness_status from batch.asset_partition where tenant_id = #{tenantId} and business_key in
#{businessKey}
order by business_key asc, asset_code asc, partition_key asc

select source_instance_id, count(1)::bigint as record_count, count(1) filter (where dispatch_status in ('SENT', 'ACKED'))::bigint as sent_count, count(1) filter (where dispatch_status = 'FAILED')::bigint as failed_count, count(1) filter (where receipt_status = 'PENDING')::bigint as pending_receipt_count from ( select pi.related_job_instance_id as source_instance_id, fdr.dispatch_status, fdr.receipt_status from batch.file_dispatch_record fdr join batch.pipeline_instance pi on pi.tenant_id = fdr.tenant_id and pi.id = fdr.pipeline_instance_id where fdr.tenant_id = #{tenantId} and pi.related_job_instance_id in
#{sourceInstanceId}
union all select pi.related_job_instance_id as source_instance_id, fdr.dispatch_status, fdr.receipt_status from archive.file_dispatch_record_archive fdr join archive.pipeline_instance_archive pi on pi.tenant_id = fdr.tenant_id and pi.id = fdr.pipeline_instance_id where fdr.tenant_id = #{tenantId} and pi.related_job_instance_id in
#{sourceInstanceId}
) s where source_instance_id is not null group by source_instance_id order by source_instance_id asc
